SELECT DISTINCT region_id
FROM vaccination_centers
WHERE vaccines_offered LIKE '%Pfizer%';

SELECT DISTINCT u.username, u.role
FROM users u
JOIN case_updates cu ON u.user_id = cu.updated_by;

SELECT users.first_name, users.last_name, users.role
FROM users
JOIN case_updates ON users.user_id = case_updates.updated_by;

SELECT username
FROM users
WHERE role = 'data_entry';

SELECT regions.region_name, covid_cases.confirmed, covid_cases.deaths
FROM regions
INNER JOIN covid_cases ON regions.region_id = covid_cases.region_id;

SELECT case_id, updated_by, update_date, notes, change_reason
FROM case_updates
WHERE change_reason = 'new case';
